259→                    saveHintTimeoutMs(game.hintTimeout);
260→                }
261→                if (allowNonMatchingSwapsCheckbox) {
262→                    game.allowNonMatchingSwaps = allowNonMatchingSwapsCheckbox.checked;
263→                    saveAllowNonMatchingSwaps(game.allowNonMatchingSwaps);
264→                }
265→                if (extendedFreeSwapCheckbox) {
266→                    game.extendedFreeSwap = extendedFreeSwapCheckbox.checked;
267→                    saveExtendedFreeSwap(game.extendedFreeSwap);
268→                }
269→                if (formationPowerUpRewardsCheckbox) {
270→                    game.formationPowerUpRewards = formationPowerUpRewardsCheckbox.checked;
271→                    saveFormationPowerUpRewards(game.formationPowerUpRewards);
272→                }
