286→                const selectedCbs = document.querySelectorAll(".powerup-select-cb:checked");
287→                const selected = Array.from(selectedCbs).map((cb) => cb.value);
288→                if (selected.length === 3) {
289→                    game.selectedPowerUps = selected;
